parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "oneOf": [
    {
      "title": "Approved Output",
      "required": ["status", "cleaned_topic"],
      "properties": {
        "status": {
          "type": "string",
          "enum": ["approved"]
        },
        "cleaned_topic": {
          "type": "string",
          "description": "Child-friendly version of the input topic"
        }
      },
      "additionalProperties": false
    },
    {
      "title": "Rejected Output",
      "required": ["status", "reason"],
      "properties": {
        "status": {
          "type": "string",
          "enum": ["rejected"]
        },
        "reason": {
          "type": "string",
          "description": "Brief explanation for rejection"
        },
        "suggested_topic": {
          "type": "string",
          "description": "Optional safe alternative topic"
        }
      },
      "additionalProperties": false
    }
  ]
}
